 1→export function distance(a, b) {
 2→  const dx = b.x - a.x;
 3→  const dy = b.y - a.y;
 4→  return Math.sqrt(dx * dx + dy * dy);
 5→}
 6→
 7→export function midpoint(a, b) {
 8→  return { x: (a.x + b.x) / 2, y: (a.y + b.y) / 2 };
 9→}
