 40→export function createSelectHandler({ dispatch, editorDispatch, getFloor, activeFloorId, viewport }) {
 41→  return {
 42→    onMouseDown(modelPos, e, toolState) {
 43→      if (e.button !== 0) return;
 44→
 45→      const floor = getFloor(activeFloorId);
 46→      const hitRadius = 10 / viewport.zoom;
 47→
 48→      // Check if clicking a handle
 49→      const target = e.target;
 50→      if (target.dataset.handle) {
 51→        editorDispatch({
 52→          type: 'UPDATE_TOOL_STATE',
 53→          payload: {
 54→            dragging: true,
 55→            dragType: 'handle',
 56→            handle: target.dataset.handle,
 57→            startPos: modelPos,
 58→          },
 59→        });
 60→        return;
 61→      }
 62→
 63→      const hit = hitTest(modelPos, floor, hitRadius);
 64→      if (hit) {
 65→        editorDispatch({ type: 'SELECT_OBJECT', id: hit.id, objectType: hit.type });
 66→        editorDispatch({
 67→          type: 'UPDATE_TOOL_STATE',
 68→          payload: {
 69→            dragging: true,
 70→            dragType: 'move',
 71→            startPos: modelPos,
 72→            originalPos: modelPos,
 73→          },
 74→        });
 75→      } else {
 76→        editorDispatch({ type: 'DESELECT' });
 77→      }
 78→    },
 79→
 80→    onMouseMove(modelPos, e, toolState, selectedId, selectedType) {
 81→      if (!toolState.dragging || !selectedId) return;
 82→
 83→      const floor = getFloor(activeFloorId);
 84→      const dx = modelPos.x - toolState.startPos.x;
 85→      const dy = modelPos.y - toolState.startPos.y;
 86→
 87→      if (selectedType === 'wall') {
 88→        const wall = floor.walls.find(w => w.id === selectedId);
 89→        if (!wall) return;
 90→
 91→        if (toolState.dragType === 'handle') {
 92→          const handle = toolState.handle;
 93→          dispatch({
 94→            type: 'WALL_UPDATE',
 95→            floorId: activeFloorId,
 96→            wall: {
 97→              id: wall.id,
 98→              [handle]: { x: modelPos.x, y: modelPos.y },
 99→            },
100→          });
101→        } else {
102→          dispatch({
103→            type: 'WALL_UPDATE',
104→            floorId: activeFloorId,
105→            wall: {
106→              id: wall.id,
107→              start: { x: wall.start.x + dx, y: wall.start.y + dy },
108→              end: { x: wall.end.x + dx, y: wall.end.y + dy },
109→            },
110→          });
111→        }
112→        editorDispatch({
113→          type: 'UPDATE_TOOL_STATE',
114→          payload: { startPos: modelPos },
115→        });
116→      } else if (selectedType === 'door' || selectedType === 'window') {
117→        // Slide along parent wall
118→        const items = selectedType === 'door' ? floor.doors : floor.windows;
119→        const item = items.find(i => i.id === selectedId);
120→        if (!item) return;
121→
122→        const wall = floor.walls.find(w => w.id === item.wallId);
123→        if (!wall) return;
124→
125→        const newOffset = projectPointOnWall(wall, modelPos);
126→        const halfWidth = item.width / 2;
127→        const maxOffset = wallLength(wall) - halfWidth;
128→        const clampedOffset = Math.max(halfWidth, Math.min(maxOffset, newOffset));
129→
130→        const updateType = selectedType === 'door' ? 'DOOR_UPDATE' : 'WINDOW_UPDATE';
131→        dispatch({
132→          type: updateType,
133→          floorId: activeFloorId,
134→          [selectedType]: { id: item.id, offset: clampedOffset },
135→        });
136→
137→        editorDispatch({
138→          type: 'UPDATE_TOOL_STATE',
139→          payload: { startPos: modelPos },
140→        });
141→      }
142→    },
143→
144→    onMouseUp(modelPos, e, toolState) {
145→      if (toolState.dragging) {
146→        editorDispatch({
147→          type: 'UPDATE_TOOL_STATE',
148→          payload: { dragging: false, dragType: null, handle: null },
149→        });
150→      }
151→    },
152→
153→    onKeyDown(e, toolState, selectedId, selectedType) {
154→      if ((e.key === 'Delete' || e.key === 'Backspace') && selectedId) {
155→        const floor = getFloor(activeFloorId);
156→        if (selectedType === 'wall') {
157→          dispatch({ type: 'WALL_DELETE', floorId: activeFloorId, wallId: selectedId });
158→        } else if (selectedType === 'door') {
159→          dispatch({ type: 'DOOR_DELETE', floorId: activeFloorId, doorId: selectedId });
160→        } else if (selectedType === 'window') {
161→          dispatch({ type: 'WINDOW_DELETE', floorId: activeFloorId, windowId: selectedId });
162→        }
163→        editorDispatch({ type: 'DESELECT' });
164→      }
165→    },
166→
167→    getCursor(toolState) {
168→      if (toolState.dragging) return 'grabbing';
169→      return 'default';
170→    },
171→  };
172→}
