 1→export function polygonArea(points) {
 2→  let area = 0;
 3→  const n = points.length;
 4→  for (let i = 0; i < n; i++) {
 5→    const j = (i + 1) % n;
 6→    area += points[i].x * points[j].y;
 7→    area -= points[j].x * points[i].y;
 8→  }
 9→  return Math.abs(area) / 2;
10→}
11→
12→export function polygonCentroid(points) {
13→  let cx = 0, cy = 0;
14→  const n = points.length;
15→  for (let i = 0; i < n; i++) {
16→    cx += points[i].x;
17→    cy += points[i].y;
18→  }
19→  return { x: cx / n, y: cy / n };
20→}
21→
22→export function pointInPolygon(point, polygon) {
23→  let inside = false;
24→  const n = polygon.length;
25→  for (let i = 0, j = n - 1; i < n; j = i++) {
26→    const xi = polygon[i].x, yi = polygon[i].y;
27→    const xj = polygon[j].x, yj = polygon[j].y;
28→    if (
29→      yi > point.y !== yj > point.y &&
30→      point.x < ((xj - xi) * (point.y - yi)) / (yj - yi) + xi
31→    ) {
32→      inside = !inside;
33→    }
34→  }
35→  return inside;
36→}
